'use client';

import React, { useEffect, useRef } from 'react';

const embeddedMedia = {
  type: 'video',
  src: `data:video/mp4;base64,`
};
const defaultSettings = {
  "dotSize": 31,
  "angle": 0,
  "contrast": 0,
  "spread": 0,
  "shape": "Circle",
  "pageBackground": "#f2f1e8",
  "paperColor": "#f2f1e8",
  "inkColor": "#2b2b2b",
  "colorMode": false,
  "inverted": false,
  "smoothing": 0,
  "ditherType": "None",
  "grainMixer": 0,
  "grainOverlay": 0,
  "grainSize": 0
};
const defaultOptions = {
  "transparentBackground": true,
  "alphaMaskGradient": true,
  "pauseWhenOffscreen": true,
  "enableInteraction": false,
  "fadeIn": true,
  "autoplay": true
};
const defaultRender = {
  width: 565,
  height: 720,
  scaleFactor: 1
};

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function applyBoxBlur(cellValues, numRows, numCols, strength) {
  var result = new Float32Array(cellValues);
  var passes = Math.floor(strength);
  for (var pass = 0; pass < passes; pass += 1) {
    var temp = new Float32Array(result.length);
    for (var row = 0; row < numRows; row += 1) {
      for (var col = 0; col < numCols; col += 1) {
        var sum = 0;
        var count = 0;
        for (var dy = -1; dy <= 1; dy += 1) {
          for (var dx = -1; dx <= 1; dx += 1) {
            var sampleRow = row + dy;
            var sampleCol = col + dx;
            if (sampleRow >= 0 && sampleRow < numRows && sampleCol >= 0 && sampleCol < numCols) {
              sum += result[sampleRow * numCols + sampleCol];
              count += 1;
            }
          }
        }
        temp[row * numCols + col] = sum / count;
      }
    }
    result = temp;
  }
  var fractional = strength - Math.floor(strength);
  if (fractional > 0) {
    for (var i = 0; i < result.length; i += 1) {
      result[i] = cellValues[i] * (1 - fractional) + result[i] * fractional;
    }
  }
  return result;
}

function applyFloydSteinbergDithering(cellValues, numRows, numCols) {
  var threshold = 128;
  for (var row = 0; row < numRows; row += 1) {
    for (var col = 0; col < numCols; col += 1) {
      var index = row * numCols + col;
      var oldValue = cellValues[index];
      var newValue = oldValue < threshold ? 0 : 255;
      var error = oldValue - newValue;
      cellValues[index] = newValue;
      if (col + 1 < numCols) {
        cellValues[row * numCols + (col + 1)] += error * (7 / 16);
      }
      if (row + 1 < numRows) {
        if (col - 1 >= 0) {
          cellValues[(row + 1) * numCols + (col - 1)] += error * (3 / 16);
        }
        cellValues[(row + 1) * numCols + col] += error * (5 / 16);
        if (col + 1 < numCols) {
          cellValues[(row + 1) * numCols + (col + 1)] += error * (1 / 16);
        }
      }
    }
  }
}

function applyOrderedDithering(cellValues, numRows, numCols) {
  var bayerMatrix = [[0, 2], [3, 1]];
  var matrixSize = 2;
  for (var row = 0; row < numRows; row += 1) {
    for (var col = 0; col < numCols; col += 1) {
      var index = row * numCols + col;
      var threshold = (bayerMatrix[row % matrixSize][col % matrixSize] + 0.5) * (255 / (matrixSize * matrixSize));
      cellValues[index] = cellValues[index] < threshold ? 0 : 255;
    }
  }
}

function applyNoiseDithering(cellValues) {
  var threshold = 128;
  for (var index = 0; index < cellValues.length; index += 1) {
    var noise = (Math.random() - 0.5) * 50;
    var adjustedValue = cellValues[index] + noise;
    cellValues[index] = adjustedValue < threshold ? 0 : 255;
  }
}

function sampleGrayAt(grayData, width, height, x, y) {
  var sampleX = clamp(Math.round(x), 0, width - 1);
  var sampleY = clamp(Math.round(y), 0, height - 1);
  return grayData[sampleY * width + sampleX];
}

function sampleRgbAt(data, width, height, x, y) {
  var sampleX = clamp(Math.round(x), 0, width - 1);
  var sampleY = clamp(Math.round(y), 0, height - 1);
  var index = (sampleY * width + sampleX) * 4;
  return [data[index], data[index + 1], data[index + 2]];
}

function pseudoRandom2d(x, y, seed) {
  var raw = Math.sin(x * 127.1 + y * 311.7 + seed * 74.7) * 43758.5453;
  return raw - Math.floor(raw);
}

function fract(value) {
  return value - Math.floor(value);
}

function smoothstep(edge0, edge1, value) {
  if (Math.abs(edge1 - edge0) < 1e-6) {
    return value >= edge1 ? 1 : 0;
  }
  var t = clamp((value - edge0) / (edge1 - edge0), 0, 1);
  return t * t * (3 - 2 * t);
}

function hash21(x, y) {
  var px = fract(x * 0.3183099) + 0.1;
  var py = fract(y * 0.3678794) + 0.1;
  var dotTerm = px * (px + 19.19) + py * (py + 19.19);
  px += dotTerm;
  py += dotTerm;
  return fract(px * py);
}

function valueNoise2d(x, y) {
  var ix = Math.floor(x);
  var iy = Math.floor(y);
  var fx = fract(x);
  var fy = fract(y);
  var a = hash21(ix, iy);
  var b = hash21(ix + 1, iy);
  var c = hash21(ix, iy + 1);
  var d = hash21(ix + 1, iy + 1);
  var ux = fx * fx * (3 - 2 * fx);
  var uy = fy * fy * (3 - 2 * fy);
  var x1 = a + (b - a) * ux;
  var x2 = c + (d - c) * ux;
  return x1 + (x2 - x1) * uy;
}

function rotateVec2(x, y, angleRadians) {
  var cosAngle = Math.cos(angleRadians);
  var sinAngle = Math.sin(angleRadians);
  return [cosAngle * x - sinAngle * y, sinAngle * x + cosAngle * y];
}

function getGrainUv(imageU, imageV, grainSize, imageAspectRatio) {
  var clampedSize = clamp(grainSize, 0, 1);
  var grainScale = 2000 + (200 - 2000) * clampedSize;
  var scaledAspect = Math.max(1e-5, imageAspectRatio);
  var grainU = imageU - 0.5;
  var grainV = imageV - 0.5;
  grainU *= grainScale;
  grainV *= grainScale * (1 / scaledAspect);
  grainU += 0.5;
  grainV += 0.5;
  return [grainU, grainV];
}

function getGrainMixerAmount(grainU, grainV, grainMixer) {
  var clampedMixer = clamp(grainMixer, 0, 1);
  if (clampedMixer <= 0) {
    return 0;
  }
  var grain = valueNoise2d(grainU, grainV);
  grain = smoothstep(0.55, 0.7 + 0.2 * clampedMixer, grain);
  return grain * clampedMixer;
}

function getGrainOverlaySample(grainU, grainV, grainOverlay) {
  var clampedOverlay = clamp(grainOverlay, 0, 1);
  if (clampedOverlay <= 0) {
    return { isWhite: true, strength: 0 };
  }
  var rotated1 = rotateVec2(grainU, grainV, 1);
  var overlay = valueNoise2d(rotated1[0] + 3, rotated1[1] + 3);
  var rotated2 = rotateVec2(grainU, grainV, 2);
  overlay = overlay * 0.5 + valueNoise2d(rotated2[0] - 1, rotated2[1] - 1) * 0.5;
  overlay = Math.pow(overlay, 1.3);
  var overlayValue = overlay * 2 - 1;
  var strength = clampedOverlay * Math.abs(overlayValue);
  strength = Math.pow(strength, 0.8);
  return { isWhite: overlayValue >= 0, strength: strength };
}

function drawHalftoneShape(context, shape, centerX, centerY, radius, color, angleRadians) {
  context.fillStyle = color;
  context.strokeStyle = color;
  if (shape === 'Square') {
    var side = radius * 2;
    context.fillRect(centerX - side / 2, centerY - side / 2, side, side);
    return;
  }
  if (shape === 'Diamond') {
    var diamondSide = radius * Math.SQRT2;
    context.beginPath();
    context.moveTo(centerX, centerY - diamondSide);
    context.lineTo(centerX + diamondSide, centerY);
    context.lineTo(centerX, centerY + diamondSide);
    context.lineTo(centerX - diamondSide, centerY);
    context.closePath();
    context.fill();
    return;
  }
  if (shape === 'Triangle') {
    var triangleRadius = radius * 1.25;
    context.save();
    context.translate(centerX, centerY);
    context.rotate(angleRadians);
    context.beginPath();
    context.moveTo(0, -triangleRadius);
    context.lineTo(triangleRadius * 0.9, triangleRadius * 0.75);
    context.lineTo(-triangleRadius * 0.9, triangleRadius * 0.75);
    context.closePath();
    context.fill();
    context.restore();
    return;
  }
  if (shape === 'Line') {
    var lineLength = radius * 2;
    var lineThickness = Math.max(1, radius * 0.55);
    context.save();
    context.translate(centerX, centerY);
    context.rotate(angleRadians);
    context.beginPath();
    context.lineWidth = lineThickness;
    context.lineCap = 'round';
    context.moveTo(-lineLength / 2, 0);
    context.lineTo(lineLength / 2, 0);
    context.stroke();
    context.restore();
    return;
  }
  context.beginPath();
  context.arc(centerX, centerY, radius, 0, Math.PI * 2);
  context.fill();
}

function renderHalftoneFrame(targetCanvas, sourceElement, settings, scaleFactor, options) {
  var targetWidth = targetCanvas.width;
  var targetHeight = targetCanvas.height;
  var tempCanvas = document.createElement('canvas');
  tempCanvas.width = targetWidth;
  tempCanvas.height = targetHeight;
  var tempContext = tempCanvas.getContext('2d', { willReadFrequently: true });
  if (!tempContext) return;

  var sourceWidth = sourceElement.videoWidth || sourceElement.naturalWidth || sourceElement.width || targetWidth;
  var sourceHeight = sourceElement.videoHeight || sourceElement.naturalHeight || sourceElement.height || targetHeight;

  if (sourceWidth > 0 && sourceHeight > 0) {
    var sourceAspect = sourceWidth / sourceHeight;
    var targetAspect = targetWidth / targetHeight;
    var drawWidth = targetWidth;
    var drawHeight = targetHeight;
    var offsetX = 0;
    var offsetY = 0;

    if (sourceAspect > targetAspect) {
      drawHeight = targetWidth / sourceAspect;
      offsetY = (targetHeight - drawHeight) / 2;
    } else if (sourceAspect < targetAspect) {
      drawWidth = targetHeight * sourceAspect;
      offsetX = (targetWidth - drawWidth) / 2;
    }

    tempContext.clearRect(0, 0, targetWidth, targetHeight);
    tempContext.drawImage(sourceElement, offsetX, offsetY, drawWidth, drawHeight);
  } else {
    tempContext.drawImage(sourceElement, 0, 0, targetWidth, targetHeight);
  }
  var imageData = tempContext.getImageData(0, 0, targetWidth, targetHeight);
  var data = imageData.data;
  var contrastAdjustment = clamp(settings.contrast, -255, 255);
  var contrastFactor = (259 * (contrastAdjustment + 255)) / (255 * (259 - contrastAdjustment));
  var grayData = new Float32Array(targetWidth * targetHeight);

  for (var index = 0; index < data.length; index += 4) {
    var gray = 0.299 * data[index] + 0.587 * data[index + 1] + 0.114 * data[index + 2];
    gray = contrastFactor * (gray - 128) + 128 + 20;
    gray = clamp(gray, 0, 255);
    grayData[index / 4] = gray;
  }

  var grid = Math.max(1, Math.round(settings.dotSize * scaleFactor));
  var angleRadians = (settings.angle * Math.PI) / 180;
  var isAxisAligned = Math.abs(settings.angle) < 0.001;
  var numCols;
  var numRows;
  var cellValues;
  var posX;
  var posY;
  var cellColors;

  if (isAxisAligned) {
    numCols = Math.ceil(targetWidth / grid);
    numRows = Math.ceil(targetHeight / grid);
    cellValues = new Float32Array(numRows * numCols);
    posX = new Float32Array(numRows * numCols);
    posY = new Float32Array(numRows * numCols);
    cellColors = new Uint8ClampedArray(numRows * numCols * 3);

    for (var row = 0; row < numRows; row += 1) {
      for (var col = 0; col < numCols; col += 1) {
        var idx = row * numCols + col;
        var sum = 0;
        var count = 0;
        var startY = row * grid;
        var startX = col * grid;
        var endY = Math.min(startY + grid, targetHeight);
        var endX = Math.min(startX + grid, targetWidth);

        for (var y = startY; y < endY; y += 1) {
          for (var x = startX; x < endX; x += 1) {
            sum += grayData[y * targetWidth + x];
            count += 1;
          }
        }

        cellValues[idx] = count > 0 ? sum / count : 0;
        posX[idx] = col * grid + grid / 2;
        posY[idx] = row * grid + grid / 2;

        if (settings.colorMode) {
          var rgb = sampleRgbAt(data, targetWidth, targetHeight, posX[idx], posY[idx]);
          var colorIndex = idx * 3;
          cellColors[colorIndex] = rgb[0];
          cellColors[colorIndex + 1] = rgb[1];
          cellColors[colorIndex + 2] = rgb[2];
        }
      }
    }
  } else {
    var diagonal = Math.ceil(Math.sqrt(targetWidth * targetWidth + targetHeight * targetHeight));
    numCols = Math.ceil(diagonal / grid) + 2;
    numRows = Math.ceil(diagonal / grid) + 2;
    var halfCols = numCols / 2;
    var halfRows = numRows / 2;
    var cosAngle = Math.cos(angleRadians);
    var sinAngle = Math.sin(angleRadians);
    var centerX = targetWidth / 2;
    var centerY = targetHeight / 2;

    cellValues = new Float32Array(numRows * numCols);
    posX = new Float32Array(numRows * numCols);
    posY = new Float32Array(numRows * numCols);
    cellColors = new Uint8ClampedArray(numRows * numCols * 3);

    for (var r = 0; r < numRows; r += 1) {
      for (var c = 0; c < numCols; c += 1) {
        var index2 = r * numCols + c;
        var localX = (c - halfCols + 0.5) * grid;
        var localY = (r - halfRows + 0.5) * grid;
        var rotatedX = centerX + localX * cosAngle - localY * sinAngle;
        var rotatedY = centerY + localX * sinAngle + localY * cosAngle;

        posX[index2] = rotatedX;
        posY[index2] = rotatedY;
        cellValues[index2] = sampleGrayAt(grayData, targetWidth, targetHeight, rotatedX, rotatedY);

        if (settings.colorMode) {
          var rgb2 = sampleRgbAt(data, targetWidth, targetHeight, rotatedX, rotatedY);
          var colorIndex2 = index2 * 3;
          cellColors[colorIndex2] = rgb2[0];
          cellColors[colorIndex2 + 1] = rgb2[1];
          cellColors[colorIndex2 + 2] = rgb2[2];
        }
      }
    }
  }

  if (settings.smoothing > 0) {
    cellValues = applyBoxBlur(cellValues, numRows, numCols, settings.smoothing);
  }
  if (settings.ditherType === 'FloydSteinberg') {
    applyFloydSteinbergDithering(cellValues, numRows, numCols);
  } else if (settings.ditherType === 'Ordered') {
    applyOrderedDithering(cellValues, numRows, numCols);
  } else if (settings.ditherType === 'Noise') {
    applyNoiseDithering(cellValues);
  }

  var context = targetCanvas.getContext('2d');
  if (!context) return;

  if (options.transparentBackground) {
    context.clearRect(0, 0, targetWidth, targetHeight);
  } else {
    context.fillStyle = settings.paperColor;
    context.fillRect(0, 0, targetWidth, targetHeight);
  }

  var maxRadius = grid / 2;
  var spreadRadius = (settings.spread / 100) * grid * 0.8;
  var grainMixer = typeof settings.grainMixer === 'number' ? clamp(settings.grainMixer, 0, 1) : 0;
  var grainOverlay = typeof settings.grainOverlay === 'number' ? clamp(settings.grainOverlay, 0, 1) : 0;
  var grainSize = typeof settings.grainSize === 'number' ? clamp(settings.grainSize, 0, 1) : 0;
  var imageAspectRatio = targetWidth / Math.max(1, targetHeight);

  for (var row2 = 0; row2 < numRows; row2 += 1) {
    for (var col2 = 0; col2 < numCols; col2 += 1) {
      var idx2 = row2 * numCols + col2;
      var brightnessValue = clamp(cellValues[idx2], 0, 255);
      var normalized = brightnessValue / 255;
      var tone = settings.inverted ? normalized : 1 - normalized;
      var finalShape = tone;

      var dotX = posX[idx2];
      var dotY = posY[idx2];
      if (spreadRadius > 0) {
        var randomX = pseudoRandom2d(col2 + 13, row2 + 29, 17);
        var randomY = pseudoRandom2d(col2 + 41, row2 + 7, 91);
        dotX += (randomX - 0.5) * spreadRadius * 2;
        dotY += (randomY - 0.5) * spreadRadius * 2;
      }

      if (dotX < -grid || dotX > targetWidth + grid || dotY < -grid || dotY > targetHeight + grid) {
        continue;
      }

      if (grainMixer > 0) {
        var imageU = clamp(dotX / targetWidth, 0, 1);
        var imageV = clamp(dotY / targetHeight, 0, 1);
        var grainUV = getGrainUv(imageU, imageV, grainSize, imageAspectRatio);
        var mixerAmount = getGrainMixerAmount(grainUV[0], grainUV[1], grainMixer);
        finalShape *= 1 - mixerAmount;
      }

      var radius = maxRadius * finalShape;
      if (radius <= 0.45) continue;

      var dotColor = settings.colorMode
        ? 'rgb(' + cellColors[idx2 * 3] + ' ' + cellColors[idx2 * 3 + 1] + ' ' + cellColors[idx2 * 3 + 2] + ')'
        : settings.inkColor;

      drawHalftoneShape(context, settings.shape, dotX, dotY, radius, dotColor, angleRadians);
    }
  }

  if (grainOverlay > 0) {
    var overlaySize = Math.max(1, grid * 0.24);
    for (var overlayRow = 0; overlayRow < numRows; overlayRow += 1) {
      for (var overlayCol = 0; overlayCol < numCols; overlayCol += 1) {
        var overlayIndex = overlayRow * numCols + overlayCol;
        var overlayX = posX[overlayIndex];
        var overlayY = posY[overlayIndex];
        if (overlayX < -grid || overlayX > targetWidth + grid || overlayY < -grid || overlayY > targetHeight + grid) {
          continue;
        }
        var imageU = clamp(overlayX / targetWidth, 0, 1);
        var imageV = clamp(overlayY / targetHeight, 0, 1);
        var overlayGrainUv = getGrainUv(imageU, imageV, grainSize, imageAspectRatio);
        var overlaySample = getGrainOverlaySample(overlayGrainUv[0], overlayGrainUv[1], grainOverlay);
        if (overlaySample.strength <= 0.01) {
          continue;
        }
        var tone = overlaySample.isWhite ? 255 : 0;
        var alpha = 0.5 * overlaySample.strength;
        context.fillStyle = 'rgba(' + tone + ', ' + tone + ', ' + tone + ', ' + alpha + ')';
        context.fillRect(overlayX - overlaySize / 2, overlayY - overlaySize / 2, overlaySize, overlaySize);
      }
    }
  }
}

function createMediaSource(type, src) {
  return new Promise(function(resolve, reject) {
    if (type === 'video') {
      var video = document.createElement('video');
      video.crossOrigin = 'anonymous';
      video.loop = true;
      video.muted = true;
      video.playsInline = true;
      video.setAttribute('webkit-playsinline', 'true');
      video.addEventListener('loadeddata', function() { resolve(video); }, { once: true });
      video.addEventListener('error', function() { reject(new Error('Failed to load video source.')); }, { once: true });
      video.src = src;
      video.load();
      return;
    }

    var image = new Image();
    image.crossOrigin = 'anonymous';
    image.addEventListener('load', function() { resolve(image); }, { once: true });
    image.addEventListener('error', function() { reject(new Error('Failed to load image source.')); }, { once: true });
    image.src = src;
  });
}

async function mountHalftoneRuntime(host, config) {
  var media = config.media;
  var settings = config.settings;
  var options = config.options;
  var render = config.render;

  host.style.position = host.style.position || 'relative';
  host.style.overflow = host.style.overflow || 'hidden';

  var canvas = document.createElement('canvas');
  canvas.width = Math.max(1, Math.round(render.width));
  canvas.height = Math.max(1, Math.round(render.height));
  canvas.style.width = '100%';
  canvas.style.height = '100%';
  canvas.style.objectFit = 'contain';
  canvas.style.display = 'block';
  canvas.style.willChange = 'transform, opacity';
  canvas.style.opacity = options.fadeIn ? '0' : '1';

  host.replaceChildren(canvas);

  var source = await createMediaSource(media.type, media.src);
  if (options.fadeIn) {
    requestAnimationFrame(function() {
      canvas.style.transition = 'opacity 420ms ease';
      canvas.style.opacity = '1';
    });
  }

  var running = true;
  var raf = 0;
  var visible = true;
  var renderedImage = false;

  if (media.type === 'video' && options.autoplay !== false) {
    source.play().catch(function() {});
  }

  var draw = function() {
    if (!running) return;

    if (media.type === 'video') {
      if (!options.pauseWhenOffscreen || visible) {
        renderHalftoneFrame(canvas, source, settings, render.scaleFactor, options);
      }
      if (options.autoplay !== false) {
        raf = requestAnimationFrame(draw);
      }
    } else if (!renderedImage) {
      renderHalftoneFrame(canvas, source, settings, render.scaleFactor, options);
      renderedImage = true;
    }
  };

  draw();

  var observer = null;
  if (options.pauseWhenOffscreen && typeof IntersectionObserver !== 'undefined') {
    observer = new IntersectionObserver(function(entries) {
      visible = entries.some(function(entry) { return entry.isIntersecting; });
      if (media.type === 'video' && options.autoplay !== false) {
        if (visible) {
          source.play().catch(function() {});
        } else {
          source.pause();
        }
      }
    });
    observer.observe(host);
  }

  var handlePointerMove = function(event) {
    if (!options.enableInteraction) return;
    var bounds = canvas.getBoundingClientRect();
    var nx = (event.clientX - bounds.left) / bounds.width - 0.5;
    var ny = (event.clientY - bounds.top) / bounds.height - 0.5;
    canvas.style.transform = 'scale(1.01) translate(' + (nx * 8).toFixed(2) + 'px, ' + (ny * 8).toFixed(2) + 'px)';
  };

  var handlePointerLeave = function() {
    canvas.style.transform = 'none';
  };

  if (options.enableInteraction) {
    canvas.addEventListener('pointermove', handlePointerMove);
    canvas.addEventListener('pointerleave', handlePointerLeave);
  }

  return function cleanup() {
    running = false;
    if (raf) {
      cancelAnimationFrame(raf);
    }
    if (observer) {
      observer.disconnect();
    }
    if (options.enableInteraction) {
      canvas.removeEventListener('pointermove', handlePointerMove);
      canvas.removeEventListener('pointerleave', handlePointerLeave);
    }
    if (media.type === 'video') {
      source.pause();
      source.src = '';
      source.load();
    }
    host.replaceChildren();
  };
}


export default function HalftoneExport({
  children,
  className = '',
  style = {},
  mediaType,
  mediaSrc,
  settings = defaultSettings,
  autoplay = defaultOptions.autoplay,
  pauseWhenOffscreen = defaultOptions.pauseWhenOffscreen,
  enableInteraction = defaultOptions.enableInteraction,
  transparentBackground = defaultOptions.transparentBackground,
  alphaMaskGradient = defaultOptions.alphaMaskGradient,
  fadeIn = defaultOptions.fadeIn,
  renderWidth = defaultRender.width,
  renderHeight = defaultRender.height,
  scaleFactor = defaultRender.scaleFactor
}) {
  const renderRef = useRef(null);

  useEffect(() => {
    if (!renderRef.current) {
      return undefined;
    }

    let disposed = false;
    let cleanup = () => {};

    mountHalftoneRuntime(renderRef.current, {
      media: {
        type: mediaType || embeddedMedia.type,
        src: mediaSrc || embeddedMedia.src
      },
      settings,
      options: {
        autoplay,
        pauseWhenOffscreen,
        enableInteraction,
        transparentBackground,
        alphaMaskGradient,
        fadeIn
      },
      render: {
        width: renderWidth,
        height: renderHeight,
        scaleFactor
      }
    })
      .then((disposeFn) => {
        if (disposed) {
          disposeFn();
          return;
        }
        cleanup = disposeFn;
      })
      .catch((error) => {
        console.error('[Halftone Export]', error);
      });

    return () => {
      disposed = true;
      cleanup();
    };
  }, [
    mediaType,
    mediaSrc,
    settings,
    autoplay,
    pauseWhenOffscreen,
    enableInteraction,
    transparentBackground,
    alphaMaskGradient,
    fadeIn,
    renderWidth,
    renderHeight,
    scaleFactor
  ]);

  return (
    <div
      className={className}
      style={{
        position: 'relative',
        width: '100%',
        height: '100%',
        overflow: 'hidden',
        ...style
      }}
    >
      <div ref={renderRef} style={{ position: 'absolute', inset: 0 }} />
      {children ? <div style={{ position: 'relative', zIndex: 2 }}>{children}</div> : null}
    </div>
  );
}
